import React, { useState, useEffect } from "react";
import { GoogleLogin } from "@react-oauth/google";
import { useNavigate, Link } from "react-router-dom";
import Navbar from "../components/Navbar";
import "../App.css";

function Login() {
  const navigate = useNavigate();

  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");

  // 🔹 role comes from signup (temporary frontend logic)
  const role = localStorage.getItem("role") || "staff";

  // 🔹 Redirect based on role
  const redirectAfterLogin = () => {
    if (role === "admin") {
      navigate("/admin/dashboard");
    } else {
      navigate("/staff/dashboard");
    }
  };

  // 🔹 If already logged in, redirect automatically
  useEffect(() => {
    const token = localStorage.getItem("token");
    if (token) {
      redirectAfterLogin();
    }
  }, []);

  // 🔵 Email / Password Login
  const handleEmailLogin = (e) => {
    e.preventDefault();

    if (!email || !password) {
      alert("Please fill all fields");
      return;
    }

    // 🔐 temporary token (later backend se aayega)
    localStorage.setItem("token", "dummy-login-token");

    console.log("Email:", email);
    console.log("Password:", password);
    console.log("Role:", role);

    redirectAfterLogin();
  };

  return (
    <>
      {/* 🔹 Minimal Navbar */}
      <Navbar variant="minimal" />

      <div className="login-container">
        <div className="login-card glass">
          <h2>Welcome to RetailVision</h2>

          {/* 🔐 Role info */}
          <p
            className="note"
            style={{ textAlign: "center", marginBottom: "16px" }}
          >
            Logging in as: <strong>{role}</strong>
          </p>

          {/* 🔵 EMAIL / PASSWORD LOGIN */}
          <form onSubmit={handleEmailLogin}>
            <input
              type="email"
              placeholder="Email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required
            />

            <input
              type="password"
              placeholder="Password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
            />

            <button type="submit" className="login-btn">
              Login
            </button>
          </form>

          <div className="divider">OR</div>

          {/* 🔵 GOOGLE LOGIN */}
          <div className="google-login">
            <GoogleLogin
              onSuccess={(res) => {
                console.log("Google Token:", res.credential);

                // 🔐 save token (temporary)
                localStorage.setItem("token", res.credential);

                redirectAfterLogin();
              }}
              onError={() => {
                alert("Google Login Failed");
              }}
            />
          </div>

          <p className="note">
            New user? <Link to="/signup">Create an account</Link>
          </p>
        </div>
      </div>
    </>
  );
}

export default Login;
